<body>
    <div class="container">
        <header>
            <h1>⚔️ WASTEDTOKEN MINT ⚔️</h1>
            <p class="tagline">Legendary coins. Forged in digital fire.</p>
        </header>

        <canvas id="coin-hero"></canvas>

        <div class="about">
            <h2>About WastedToken Mint</h2>
            <p>
                Since 2019, WastedToken Mint has crafted premium collectible challenge coins 
                for gaming communities, esports teams, and digital culture enthusiasts. 
                Each coin is individually minted with exquisite detail and authentic metallic finishes. 
                Own a piece of legend. Earn your coin.
            </p>
        </div>

        <h2 class="editions-title">Current Editions</h2>

        <div class="editions">
            <div class="edition" data-edition="bronze" data-state="available">
                <canvas class="edition-canvas"></canvas>
                <h3>Bronze Edition</h3>
                <p>Classic burnished bronze with vintage patina</p>
                <button class="buy">Add to Cart</button>
            </div>

            <div class="edition" data-edition="silver" data-state="available">
                <canvas class="edition-canvas"></canvas>
                <h3>Silver Edition</h3>
                <p>Mirror-polished sterling silver finish</p>
                <button class="buy">Add to Cart</button>
            </div>

            <div class="edition" data-edition="gold" data-state="sold-out">
                <canvas class="edition-canvas"></canvas>
                <h3>Gold Edition</h3>
                <p>24k gold plating on premium brass</p>
                <div class="status sold">SOLD OUT</div>
            </div>

            <div class="edition" data-edition="black" data-state="coming-soon">
                <canvas class="edition-canvas"></canvas>
                <h3>Black Obsidian Edition</h3>
                <p>Premium matte black obsidian finish</p>
                <div class="status coming">MINTING SPRING 2027</div>
            </div>
        </div>
    </div>

    <script>
        class CoinRenderer {
            constructor(canvas, options = {}) {
                this.canvas = canvas;
                this.gl = canvas.getContext('webgl2', { antialias: true, alpha: true });

                if (!this.gl) return;

                this.time = 0;
                this.paused = false;
                this.isHero = options.isHero || false;
                this.baseColor = options.color || [0.85, 0.75, 0.55];
                this.metallic = options.metallic || 1.0;

                this.gl.clearColor(0, 0, 0, 0);
                this.gl.enable(this.gl.DEPTH_TEST);
                this.gl.enable(this.gl.CULL_FACE);
                this.resizeCanvas();

                this.createGeometry();
                this.createShaders();

                if (!options.isDemoMode) {
                    this.animate();
                }
            }

            resizeCanvas() {
                this.canvas.width = this.canvas.clientWidth * devicePixelRatio;
                this.canvas.height = this.canvas.clientHeight * devicePixelRatio;
                this.gl.viewport(0, 0, this.canvas.width, this.canvas.height);
            }

            createGeometry() {
                const gl = this.gl;
                const segments = 72;
                const ridges = 20;
                const radius = 1.0;
                const thickness = 0.12;

                let vertices = [];
                let normals = [];
                let indices = [];
                let texCoords = [];

                // Cylinder edge with ridges
                for (let i = 0; i <= segments; i++) {
                    const angle = (i / segments) * Math.PI * 2;
                    const cos = Math.cos(angle);
                    const sin = Math.sin(angle);
                    const ridgeH = thickness * (0.5 + 0.4 * Math.cos(angle * ridges));

                    vertices.push(cos * radius, ridgeH, sin * radius);
                    normals.push(cos, 0, sin);

                    vertices.push(cos * radius, -ridgeH, sin * radius);
                    normals.push(cos, 0, sin);
                }

                for (let i = 0; i < segments; i++) {
                    const a = i * 2;
                    const b = a + 2;
                    const c = a + 1;
                    const d = b + 1;
                    indices.push(a, c, b, b, c, d);
                }

                // Front face (emblem)
                const frontStart = vertices.length / 3;
                vertices.push(0, thickness, 0);
                normals.push(0, 1, 0);
                texCoords.push(0.5, 0.5);

                for (let i = 0; i <= segments; i++) {
                    const angle = (i / segments) * Math.PI * 2;
                    vertices.push(Math.cos(angle) * radius, thickness, Math.sin(angle) * radius);
                    normals.push(0, 1, 0);
                    texCoords.push(0.5 + 0.5 * Math.cos(angle), 0.5 + 0.5 * Math.sin(angle));
                }

                for (let i = 0; i < segments; i++) {
                    indices.push(frontStart, frontStart + i + 2, frontStart + i + 1);
                }

                // Back face (denomination)
                const backStart = vertices.length / 3;
                vertices.push(0, -thickness, 0);
                normals.push(0, -1, 0);
                texCoords.push(0.5, 0.5);

                for (let i = 0; i <= segments; i++) {
                    const angle = (i / segments) * Math.PI * 2;
                    vertices.push(Math.cos(angle) * radius, -thickness, Math.sin(angle) * radius);
                    normals.push(0, -1, 0);
                    texCoords.push(0.5 + 0.5 * Math.cos(angle), 0.5 + 0.5 * Math.sin(angle));
                }

                for (let i = 0; i < segments; i++) {
                    indices.push(backStart, backStart + i + 1, backStart + i + 2);
                }

                this.vertexCount = indices.length;

                const posBuffer = gl.createBuffer();
                gl.bindBuffer(gl.ARRAY_BUFFER, posBuffer);
                gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(vertices), gl.STATIC_DRAW);
                gl.vertexAttribPointer(0, 3, gl.FLOAT, false, 0, 0);
                gl.enableVertexAttribArray(0);

                const normBuffer = gl.createBuffer();
                gl.bindBuffer(gl.ARRAY_BUFFER, normBuffer);
                gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(normals), gl.STATIC_DRAW);
                gl.vertexAttribPointer(1, 3, gl.FLOAT, false, 0, 0);
                gl.enableVertexAttribArray(1);

                const texBuffer = gl.createBuffer();
                gl.bindBuffer(gl.ARRAY_BUFFER, texBuffer);
                gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(texCoords), gl.STATIC_DRAW);
                gl.vertexAttribPointer(2, 2, gl.FLOAT, false, 0, 0);
                gl.enableVertexAttribArray(2);

                const idxBuffer = gl.createBuffer();
                gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, idxBuffer);
                gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, new Uint32Array(indices), gl.STATIC_DRAW);
            }

            createShaders() {
                const gl = this.gl;

                const vShader = gl.createShader(gl.VERTEX_SHADER);
                gl.shaderSource(vShader, `#version 300 es
                    precision highp float;
                    layout(location=0) in vec3 pos;
                    layout(location=1) in vec3 norm;
                    layout(location=2) in vec2 uv;

                    uniform mat4 proj, view, model;
                    out vec3 vN, vP;
                    out vec2 vUV;

                    void main(){
                        vP = (model * vec4(pos, 1.0)).xyz;
                        vN = normalize(mat3(transpose(inverse(model))) * norm);
                        vUV = uv;
                        gl_Position = proj * view * vec4(vP, 1.0);
                    }
                `);
                gl.compileShader(vShader);

                const fShader = gl.createShader(gl.FRAGMENT_SHADER);
                gl.shaderSource(fShader, `#version 300 es
                    precision highp float;
                    in vec3 vN, vP;
                    in vec2 vUV;

                    uniform vec3 col, lp, vp;
                    uniform float met;

                    out vec4 FragColor;

                    void main(){
                        vec3 n = normalize(vN);
                        vec3 l = normalize(lp - vP);
                        vec3 v = normalize(vp - vP);
                        vec3 r = reflect(-l, n);

                        float diff = max(dot(n, l), 0.0);
                        float spec = pow(max(dot(v, r), 0.0), 40.0 * met);

                        vec3 ambient = 0.15 * col;
                        vec3 diffuse = diff * col;
                        vec3 specular = spec * vec3(1.0) * (0.8 + 0.4 * met);

                        float rim = pow(1.0 - max(dot(v, n), 0.0), 3.0);
                        vec3 rimLight = 0.2 * rim * vec3(1.0);

                        vec3 result = ambient + diffuse + specular + rimLight;
                        FragColor = vec4(result, 1.0);
                    }
                `);
                gl.compileShader(fShader);

                this.prog = gl.createProgram();
                gl.attachShader(this.prog, vShader);
                gl.attachShader(this.prog, fShader);
                gl.linkProgram(this.prog);
                gl.useProgram(this.prog);
            }

            setTime(t) {
                this.time = t;
                this.render();
            }

            render() {
                const gl = this.gl;
                gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);

                const asp = this.canvas.width / this.canvas.height;
                const proj = this.perspectiveMatrix(Math.PI / 4, asp, 0.1, 100);
                const view = this.lookAtMatrix([0, 0, 2.4], [0, 0, 0], [0, 1, 0]);

                const t = this.time;
                const ry = t * Math.PI * 2;
                const rx = Math.sin(t * Math.PI * 2) * 0.6;
                const model = this.mul(this.rotY(ry), this.rotX(rx));

                gl.uniformMatrix4fv(gl.getUniformLocation(this.prog, 'proj'), false, proj);
                gl.uniformMatrix4fv(gl.getUniformLocation(this.prog, 'view'), false, view);
                gl.uniformMatrix4fv(gl.getUniformLocation(this.prog, 'model'), false, model);
                gl.uniform3fv(gl.getUniformLocation(this.prog, 'col'), this.baseColor);
                gl.uniform3fv(gl.getUniformLocation(this.prog, 'lp'), [2.5, 1.5, 2.5]);
                gl.uniform3fv(gl.getUniformLocation(this.prog, 'vp'), [0, 0, 2.4]);
                gl.uniform1f(gl.getUniformLocation(this.prog, 'met'), this.metallic);

                gl.drawElements(gl.TRIANGLES, this.vertexCount, gl.UNSIGNED_INT, 0);
            }

            animate() {
                if (!this.paused) this.time = (this.time + 0.01) % 1;
                this.render();
                requestAnimationFrame(() => this.animate());
            }

            pause() { this.paused = true; }

            perspectiveMatrix(fov, asp, n, f) {
                const t = 1 / Math.tan(fov / 2);
                const m = new Float32Array(16);
                m[0] = t / asp; m[5] = t; m[10] = (f + n) / (n - f); m[11] = -1;
                m[14] = (2 * f * n) / (n - f);
                return m;
            }

            lookAtMatrix(e, c, u) {
                const z = this.norm([e[0]-c[0], e[1]-c[1], e[2]-c[2]]);
                const x = this.norm(this.cross(u, z));
                const y = this.cross(z, x);
                const m = new Float32Array(16);
                m[0]=x[0]; m[4]=x[1]; m[8]=x[2];
                m[1]=y[0]; m[5]=y[1]; m[9]=y[2];
                m[2]=z[0]; m[6]=z[1]; m[10]=z[2];
                m[15]=1;
                m[12] = -this.dot(x,e); m[13] = -this.dot(y,e); m[14] = -this.dot(z,e);
                return m;
            }

            rotX(a) {
                const c=Math.cos(a), s=Math.sin(a);
                const m=new Float32Array(16);
                m[0]=1; m[5]=c; m[10]=c; m[15]=1;
                m[6]=s; m[9]=-s;
                return m;
            }

            rotY(a) {
                const c=Math.cos(a), s=Math.sin(a);
                const m=new Float32Array(16);
                m[0]=c; m[5]=1; m[10]=c; m[15]=1;
                m[2]=-s; m[8]=s;
                return m;
            }

            mul(a, b) {
                const m=new Float32Array(16);
                for(let i=0;i<4;i++) for(let j=0;j<4;j++) {
                    m[i*4+j]=0;
                    for(let k=0;k<4;k++) m[i*4+j]+=a[k*4+j]*b[i*4+k];
                }
                return m;
            }

            cross(a, b) {
                return [a[1]*b[2]-a[2]*b[1], a[2]*b[0]-a[0]*b[2], a[0]*b[1]-a[1]*b[0]];
            }

            dot(a, b) { return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]; }

            norm(v) {
                const l=Math.sqrt(v[0]*v[0]+v[1]*v[1]+v[2]*v[2]);
                return [v[0]/l, v[1]/l, v[2]/l];
            }
        }

        const heroCanvas = document.getElementById('coin-hero');
        const heroCoin = new CoinRenderer(heroCanvas, {
            color: [0.88, 0.78, 0.54],
            metallic: 1.2,
            isHero: true,
            isDemoMode: false
        });

        const editionConfigs = {
            bronze: { color: [0.75, 0.48, 0.18], metallic: 0.9 },
            silver: { color: [0.92, 0.92, 0.96], metallic: 1.35 },
            gold: { color: [1.0, 0.82, 0.15], metallic: 1.45 },
            black: { color: [0.12, 0.12, 0.18], metallic: 0.65 }
        };

        document.querySelectorAll('.edition').forEach(ed => {
            const type = ed.getAttribute('data-edition');
            const canvas = ed.querySelector('.edition-canvas');
            const cfg = editionConfigs[type];
            new CoinRenderer(canvas, { color: cfg.color, metallic: cfg.metallic, isDemoMode: false });
        });

        window.demo = {
            canvas: heroCanvas,
            setTime(t) { heroCoin.setTime(Math.max(0, Math.min(1, t))); },
            pause() { heroCoin.pause(); }
        };
    </script>
</body>
